mapper.select:
SELECT * FROM ( SELECT a.account_id AS accountId, d.nickname AS nickname, d.handle AS handle, a.role_type AS roleType, a.status AS status, TO_CHAR(a.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt, ROW_NUMBER() OVER ( ORDER BY
a.created_at ASC a.created_at DESC
) rn FROM accounts a JOIN vw_account_display d ON a.account_id = d.account_id
AND d.nickname LIKE '%' || #{nickname} || '%'
AND d.handle LIKE '%' || #{handle} || '%'
AND a.role_type = #{roleType}
AND a.status = #{status}
AND a.created_at >= TO_DATE(#{createdFrom}, 'YYYY-MM-DD')
AND a.created_at < TO_DATE(#{createdTo}, 'YYYY-MM-DD') + 1
AND EXISTS ( SELECT 1 FROM reports r WHERE r.target_account_id = a.account_id AND r.status = 0 )
) WHERE rn BETWEEN (#{page}-1)*#{size}+1 AND #{page}*#{size}

mapper.update:
UPDATE accounts
SET status = #{status}
WHERE account_id
= #{accountId}

UPDATE user_profile
SET intro = '부적절한 내용이 포함되어있습니다.'
WHERE account_id = #{accountId}
